// The synthetic ensures of det_<f> has the shape `A ==> det_equal(r1,r2)`,
// where A is the conjunction of the original `ensures` clauses for both
// candidate outputs.  In the proof body, A is NOT a free hypothesis — we
// must wrap our reasoning in `if A { ... }` so the antecedent is in
// scope.  Verus then turns the body of the if-block into `A ==> (body
// post-state)`, which is exactly the ensures.
if (r1.0 == page_ptr) && (((r1.1)@).addr() == r1.0) && (((r1.1)@).is_init())
    && (((r1.1)@).value().wf())
    && (forall|i: usize|
        #![trigger ((r1.1)@).value()[i].is_empty()]
        0 <= i < 512 ==> ((r1.1)@).value()[i].is_empty())
    && (r2.0 == page_ptr) && (((r2.1)@).addr() == r2.0) && (((r2.1)@).is_init())
    && (((r2.1)@).value().wf())
    && (forall|i: usize|
        #![trigger ((r2.1)@).value()[i].is_empty()]
        0 <= i < 512 ==> ((r2.1)@).value()[i].is_empty()) {

    // --- Scalar conjuncts of det_page_perm_to_page_map_equal ---
    // r1.0 == page_ptr == r2.0
    assert(r1.0 == r2.0);
    // both is_init() are true
    assert(((r1.1)@).is_init() == ((r2.1)@).is_init());
    // both addr() == page_ptr
    assert(((r1.1)@).addr() == ((r2.1)@).addr());

    // --- Set up the spec_seq lengths from wf() ---
    assert((((r1.1)@).value().spec_seq)@.len() == 512);
    assert((((r2.1)@).value().spec_seq)@.len() == 512);

    // --- Re-assert each is_empty forall with a matching trigger so
    // --- both fire on the same index inside the assert-forall below. ---
    assert(forall|i: usize|
        #![trigger ((r1.1)@).value()[i].is_empty()]
        0 <= i < 512 ==> ((r1.1)@).value()[i].is_empty());
    assert(forall|i: usize|
        #![trigger ((r2.1)@).value()[i].is_empty()]
        0 <= i < 512 ==> ((r2.1)@).value()[i].is_empty());

    // --- Pointwise spec_seq equality.
    // value()[i] = spec_seq@[i as int] (PageMap::spec_index), and
    // PageEntry::is_empty() pins every field of the entry: addr == 0,
    // perm.{present, ps, write, execute_disable, user} == false.  So
    // both spec_seq@[i] are equal to the same canonical empty entry.
    assert forall|i: int| 0 <= i < 512 implies
        (((r1.1)@).value().spec_seq)@[i] == (((r2.1)@).value().spec_seq)@[i] by {
        let iu = i as usize;
        assert(0 <= iu < 512);
        // fire both foralls on the same usize index
        assert(((r1.1)@).value()[iu].is_empty());
        assert(((r2.1)@).value()[iu].is_empty());
        // spec_index unfolds value()[iu] to spec_seq@[iu as int]
        assert((((r1.1)@).value().spec_seq)@[iu as int] == ((r1.1)@).value()[iu]);
        assert((((r2.1)@).value().spec_seq)@[iu as int] == ((r2.1)@).value()[iu]);
        // Both entries are is_empty, hence fully pinned to the same
        // canonical PageEntry value.
    }

    // --- Lift the pointwise spec_seq equality to Seq extensional eq.
    assert((((r1.1)@).value().spec_seq)@ =~= (((r2.1)@).value().spec_seq)@);

    // --- Try to close the PageMapView equality with extensionality.
    // PageMapView has fields { ar, spec_seq }; the spec_seq field is
    // now provably equal.  We also push the ar correspondence via
    // wf(): usize2page_entry(ar@[i]) =~= spec_seq@[i] on both sides,
    // and the spec_seqs are equal, so the per-index usize2page_entry
    // outputs match.
    assert forall|i: int| 0 <= i < 512 implies
        usize2page_entry((((r1.1)@).value().ar)@[i])
            == usize2page_entry((((r2.1)@).value().ar)@[i]) by {
        assert(usize2page_entry((((r1.1)@).value().ar)@[i])
            =~= (((r1.1)@).value().spec_seq)@[i]);
        assert(usize2page_entry((((r2.1)@).value().ar)@[i])
            =~= (((r2.1)@).value().spec_seq)@[i]);
        assert((((r1.1)@).value().spec_seq)@[i] == (((r2.1)@).value().spec_seq)@[i]);
    }

    // --- Try the PageMapView extensional equality (last hint).  If
    // Verus can decide the ar field equal from the per-index
    // usize2page_entry match (e.g. via the view-axiom for Array<usize,
    // N>), this closes; otherwise we've at least nailed all the
    // other conjuncts of det_equal.
    assert(((r1.1)@).value().view() =~= ((r2.1)@).value().view());
}
